import { useState } from "react";
function ChangePasswordPage() {
    let [firstinput, changenameinput] = useState("");
    let [secondinput, changepasswordinput] = useState("");
    function firstinput1() {
        let firstinput = document.querySelectorAll("input")[0].value;
        changenameinput(firstinput);
    }
    function secondinput2() {
        let secondinput = document.querySelectorAll("input")[1].value;
        changepasswordinput(secondinput);
    }
    async function func1() {
        if (firstinput !== secondinput) {
            alert("Passwords do not match");
            return;
        }
        }
  return (
    <div>
      <h1>Enter your new password</h1>
      <input onChange={() => firstinput1()} type="password" placeholder="New Password" />
      <input onChange={() => secondinput2()} type="password" placeholder="Confirm New Password" />
      <button onClick={() => func1()}>Change Password</button>
    </div>
  );
}
export default ChangePasswordPage
